app.post('/api/plugin-update-mode/:pluginId',async(req,res)=>{try{const{token}=req.query;if(!sessions[token])return res.status(401).json({error:'请先登录'});const pluginId=req.params.pluginId;const{modeIndex,enabled}=req.body;const plugin=plugins.find(p=>p.id===pluginId);if(!plugin)return res.status(404).json({error:'插件不存在'});const txtPath=path.join(plugin.extractedPath,'config.txt');let txtContent=await fs.readFile(txtPath,'utf8');const lines=txtContent.split('\n');let newLines=[];let modeCounter=0;for(let line of lines){if(line.trim().startsWith('execute')){if(modeCounter===modeIndex){const parts=line.match(/^(execute\s+.+?\|\s*"[^"]+"\s*"[^"]+"\s*)"([^"]+)"$/);if(parts){const newEnabled=enabled?'true':'false';line=parts[1]+'"'+newEnabled+'"';}}modeCounter++;}newLines.push(line);}await fs.writeFile(txtPath,newLines.join('\n'),'utf8');addLog(`更新插件模式状态: ${pluginId} 模式${modeIndex}=${enabled}`);res.json({success:true});}catch(e){res.status(500).json({error:e.message});}});
