async function loadPlugins(){plugins=[];try{const files=await fs.readdir(PLUGINS_DIR);let loadedPlugins=[];let pluginNames=new Set();for(const file of files){if(file.endsWith('.zip')){const pluginPath=path.join(PLUGINS_DIR,file);const pluginId=path.basename(file,'.zip');if(pluginNames.has(pluginId))continue;pluginNames.add(pluginId);const extractPath=path.join(PLUGINS_CACHE_DIR,pluginId);let isExtracted=false;try{await fs.access(extractPath);isExtracted=true;}catch(e){isExtracted=false;}if(!isExtracted){addLog(`解压插件: ${pluginId}`);try{const zip=new AdmZip(pluginPath);zip.extractAllTo(extractPath,true);}catch(e){addLog(`❌ 解压插件失败: ${pluginId} - ${e.message}`);continue;}}else{addLog(`使用缓存: ${pluginId}`);}try{let pluginName=pluginId;let pluginDescription='';let pluginDanger=1;let pluginVersion='v1.0.0';let pluginMdContent='';let hasPanel=false;let configFile=false;let pluginModes=[];let isSystemPlugin=false;const entries=await fs.readdir(extractPath);const jsonFile=entries.find(f=>f.toLowerCase().endsWith('.json'));if(jsonFile){try{const jsonPath=path.join(extractPath,jsonFile);const content=await fs.readFile(jsonPath,'utf8');const jsonData=JSON.parse(content);pluginName=jsonData.Name||pluginName;pluginDescription=jsonData.intro||pluginDescription;pluginDanger=jsonData.Danger||1;pluginVersion=jsonData.Ver||'v1.0.0';hasPanel=!!jsonData.hasPanel;isSystemPlugin=jsonData.System===true;}catch(e){}}const mdFile=entries.find(f=>f.endsWith('.md'));if(mdFile){try{const mdPath=path.join(extractPath,mdFile);pluginMdContent=await fs.readFile(mdPath,'utf8');if(!pluginDescription){pluginDescription=pluginMdContent.split('\n')[0].replace('#','').trim();}}catch(e){}}const txtFile=entries.find(f=>f.endsWith('.txt'));if(txtFile){try{const txtPath=path.join(extractPath,txtFile);const txtContent=await fs.readFile(txtPath,'utf8');pluginModes=parsePluginModes(txtContent);addLog(`解析到${pluginModes.length}个模式: ${JSON.stringify(pluginModes)}`);if(pluginModes.length>0){hasPanel=true;configFile=true;}}catch(e){addLog(`解析txt失败: ${e.message}`);}}const voeDir=path.join(extractPath,'voe');try{await fs.mkdir(voeDir,{recursive:true});}catch(e){}const modeConfigPath=path.join(voeDir,'mode_config.json');let modeConfig={};try{const data=await fs.readFile(modeConfigPath,'utf8');modeConfig=JSON.parse(data);}catch(e){}for(let i=0;i<pluginModes.length;i++){if(modeConfig[`mode_${i}`]!==undefined){pluginModes[i].defaultEnabled=modeConfig[`mode_${i}`];}}let enabled=true;try{const pluginConfigPath=path.join(PLUGINS_DIR,'plugins_config.json');const configData=await fs.readFile(pluginConfigPath,'utf8');const pluginConfig=JSON.parse(configData);if(pluginConfig[pluginId]&&pluginConfig[pluginId].enabled!==undefined){enabled=pluginConfig[pluginId].enabled;}}catch(e){}const pluginInfo={id:pluginId,name:pluginName,description:pluginDescription,mdContent:pluginMdContent,danger:pluginDanger,version:pluginVersion,functions:[],enabled:enabled,path:pluginPath,extractedPath:extractPath,functionSchemas:[],hasPanel:hasPanel,configFile:configFile,pluginModes:pluginModes,voePath:voeDir,system:isSystemPlugin};const pyFiles=entries.filter(f=>f.endsWith('.py'));for(const pyFile of pyFiles){const funcName=path.basename(pyFile,'.py');const funcPath=path.join(extractPath,pyFile);try{const content=await fs.readFile(funcPath,'utf8');const schemaMatch=content.match(/FUNCTION_SCHEMA\s*=\s*({[\s\S]*?})\n/);if(schemaMatch){try{const schema=JSON.parse(schemaMatch[1]);pluginInfo.functionSchemas.push({name:funcName,schema});}catch(e){}}pluginInfo.functions.push(funcName);}catch(e){}}if(pluginInfo.functions.length>0||pluginModes.length>0){plugins.push(pluginInfo);loadedPlugins.push(`${pluginName}(${pluginInfo.functions.length}个函数${pluginModes.length>0?','+pluginModes.length+'个模式':''})${hasPanel?'[有控制面板]':''}${isSystemPlugin?'[系统]':''}`);}}catch(e){addLog(`❌ 加载插件失败: ${file} - ${e.message}`,'error');}}}if(loadedPlugins.length>0){addLog(`加载插件: ${loadedPlugins.join(', ')}`,'plugin');}}catch(e){addLog(`❌ 读取插件目录失败: ${e.message}`,'error');}}

function parsePluginModes(txt){const modes=[];const lines=txt.split('\n');for(let line of lines){line=line.trim();if(!line||line.startsWith('#'))continue;const match=line.match(/^execute\s+(.+?)\s*\|\s*"([^"]+)"\s*"([^"]+)"\s*"([^"]+)"/);if(match){const filesPart=match[1].trim();const name=match[2];const desc=match[3];const defaultEnabled=match[4].toLowerCase()==='true';let type='sync';let files=[];if(filesPart.includes('|')){type='sync';files=filesPart.split('|').map(f=>f.trim());}else if(filesPart.includes('/')){type='sequential';files=filesPart.split('/').map(f=>f.trim());}else{files=[filesPart];}modes.push({name,desc,defaultEnabled,type,files});}}return modes;}
async function callPluginMode(plugin, modeIndex, args){try{const mode=plugin.pluginModes[modeIndex];if(!mode)return{success:false,error:'模式不存在'};const modeConfigPath=path.join(plugin.voePath,'mode_config.json');let modeConfig={};try{const data=await fs.readFile(modeConfigPath,'utf8');modeConfig=JSON.parse(data);}catch(e){}const enabled=modeConfig[`mode_${modeIndex}`]!==undefined?modeConfig[`mode_${modeIndex}`]:mode.defaultEnabled;if(!enabled)return{success:false,error:`模式 ${mode.name} 未启用`};addLog(`🔧 执行插件模式: ${plugin.name} - ${mode.name} (${mode.type})`);let finalOutput='';if(mode.type==='sync'){const results=await Promise.all(mode.files.map(async(file)=>{const funcName=path.basename(file,'.py');const result=await callPluginFunction(plugin.id,funcName,args);return result;}));finalOutput=results.map(r=>r.output||r.error).join('\n');const allSuccess=results.every(r=>r.success);return{success:allSuccess,output:finalOutput,error:allSuccess?null:results.filter(r=>!r.success).map(r=>r.error).join('\n')};}else{for(const file of mode.files){const funcName=path.basename(file,'.py');const result=await callPluginFunction(plugin.id,funcName,args);if(!result.success){return{success:false,output:finalOutput,error:`执行 ${funcName} 失败: ${result.error}`};}finalOutput+=result.output+'\n';}return{success:true,output:finalOutput};}}catch(e){return{success:false,error:e.message};}}

