app.post('/api/plugin-import-providers/:pluginId/:code',async(req,res)=>{try{const{token}=req.query;if(!sessions[token])return res.status(401).json({error:'请先登录'});const username=sessions[token].username;const pluginId=req.params.pluginId;const code=req.params.code;const{providerIds}=req.body;const plugin=plugins.find(p=>p.id===pluginId);if(!plugin)return res.status(404).json({error:'插件不存在'});const userProviders=await loadUserConfig(username,'providers.json',providers);const selectedProviders=userProviders.filter(p=>providerIds.includes(p.id)&&p.enabled!==false);const configPath=path.join(plugin.voePath,'config.json');let config={};try{const data=await fs.readFile(configPath,'utf8');config=JSON.parse(data);}catch(e){}config.importedProviders=selectedProviders.map(p=>({id:p.id,name:p.name,icon:p.icon,keys:p.keys||[],url:p.url,models:p.models||[]}));await fs.writeFile(configPath,JSON.stringify(config,null,2));res.json({success:true,providers:config.importedProviders});}catch(e){res.status(500).json({error:e.message});}});
