async function callPluginFunction(pluginId,functionName,args){addLog(`尝试调用插件函数: ${functionName}`);let plugin=null;let targetFile=null;for(const p of plugins){if(p.id===pluginId||p.id===functionName||p.name===functionName){plugin=p;if(p.pluginModes&&p.pluginModes.length>0){const modeConfigPath=path.join(p.voePath,'mode_config.json');let modeConfig={};try{const data=await fs.readFile(modeConfigPath,'utf8');modeConfig=JSON.parse(data);}catch(e){}let enabledMode=null;for(let i=0;i<p.pluginModes.length;i++){const mode=p.pluginModes[i];const isEnabled=modeConfig[`mode_${i}`]!==undefined?modeConfig[`mode_${i}`]:mode.defaultEnabled;if(isEnabled){enabledMode=mode;break;}}if(enabledMode){targetFile=enabledMode.files[0];addLog(`使用启用的模式: ${enabledMode.name}, 文件: ${targetFile}`);}else if(p.pluginModes.length>0){targetFile=p.pluginModes[0].files[0];addLog(`没有启用的模式，使用第一个: ${targetFile}`);}}else if(p.functions&&p.functions.length>0){targetFile=`${p.functions[0]}.py`;}break;}if(p.functions&&p.functions.includes(functionName)){plugin=p;targetFile=`${functionName}.py`;break;}}if(!plugin){addLog(`❌ 找不到插件: ${functionName}`);return{success:false,error:'插件不存在'};}if(!plugin.enabled){addLog(`❌ 插件未启用: ${plugin.name}`);return{success:false,error:'插件未启用'};}let actualFunctionName=functionName;if(targetFile){actualFunctionName=path.basename(targetFile,'.py');addLog(`实际执行文件: ${actualFunctionName}.py`);}try{const functionPath=path.join(plugin.extractedPath,`${actualFunctionName}.py`);addLog(`📁 插件函数路径: ${functionPath}`);try{await fs.access(functionPath);addLog(`插件文件存在`);const{spawn}=require('child_process');return await new Promise((resolve)=>{addLog(`执行Python脚本: ${actualFunctionName}.py`);const child=spawn('python',[functionPath],{env:{...process.env,PYTHONIOENCODING:'utf-8'}});let output='';let error='';child.stdout.on('data',(data)=>{output+=data.toString();});child.stderr.on('data',(data)=>{error+=data.toString();addLog(`⚠️ Python错误: ${data.toString()}`);});child.on('close',(code)=>{if(code!==0){addLog(`执行失败,退出码: ${code},错误: ${error}`);resolve({success:false,error:error||`退出码: ${code}`});}else{const result=output.trim();addLog(`执行成功,输出: ${result}`);const username=Object.keys(sessions).find(key=>sessions[key]&&sessions[key].username)?.username;if(username){recordModelCall(username,plugin.id,functionName);}resolve({success:true,output:result});}});const inputData=JSON.stringify({function:actualFunctionName,args:args})+'\n';addLog(`发送到stdin: ${inputData}`);child.stdin.write(inputData);child.stdin.end();});}catch(e){addLog(`❌ 插件文件不存在: ${functionPath}`);return{success:false,error:'插件文件不存在'};}}catch(e){addLog(`❌ 未知错误: ${e.message}`);return{success:false,error:e.message};}}
