async function loadFolderStatus(){try{const data=await fs.readFile(FOLDER_STATUS_FILE,'utf8');return JSON.parse(data);}catch{return{};}}
async function saveFolderStatus(status){await fs.writeFile(FOLDER_STATUS_FILE,JSON.stringify(status,null,2));}
async function loadPrivateChats(){try{const data=await fs.readFile(PRIVATE_CHATS_FILE,'utf8');privateChats=JSON.parse(data);}catch{privateChats={};}}
async function savePrivateChats(){await fs.writeFile(PRIVATE_CHATS_FILE,JSON.stringify(privateChats,null,2));}
function addLog(msg,type='info'){const t=new Date().toLocaleString('zh-CN',{hour12:false});let coloredMsg=msg;if(type==='user'){coloredMsg=`\x1b[33m${msg}\x1b[0m`;}else if(type==='api'){coloredMsg=`\x1b[36m${msg}\x1b[0m`;}else if(type==='plugin'){coloredMsg=`\x1b[36m${msg}\x1b[0m`;}else if(type==='error'){coloredMsg=`\x1b[31m${msg}\x1b[0m`;}else{coloredMsg=`\x1b[32m${msg}\x1b[0m`;}const entry={time:t,msg,type};if(msg.includes('API调用')||msg.includes('聊天请求')||msg.includes('获取模型列表')||msg.includes('余额查询')||msg.includes('CURL')||msg.includes('插件')){apiCallCount++;entry.apiCall=true;};io.emit('serverLog',entry);console.log(`[${t}] ${coloredMsg}`);}
async function fetchModelsFromProvider(provider){try{const activeKey=provider.keys?.find(k=>k.isActive)?.key;if(!activeKey||!provider.modelsUrl){addLog(`${provider.name}: 缺少有效Key或ModelsUrl`);return[];}addLog(`正在获取${provider.name}模型列表: ${provider.modelsUrl}`);const response=await axios.get(provider.modelsUrl,{headers:{'Authorization':`Bearer ${activeKey}`},timeout:10000});if(response.data?.data&&Array.isArray(response.data.data)){const models=response.data.data.map(m=>m.id);addLog(`${provider.name}: 获取到 ${models.length} 个模型: ${models.join(', ')}`);return models;}addLog(`⚠️ ${provider.name}: 返回格式异常`);return[];}catch(e){addLog(`❌ ${provider.name}获取模型列表失败: ${e.message}`);return[];}}
async function getPluginTools(){const tools=[];for(const plugin of plugins){if(plugin.enabled){for(const func of plugin.functions){tools.push({type:'function',function:{name:plugin.name,description:plugin.mdContent||plugin.description||`调用${plugin.name}插件`,parameters:{type:'object',properties:{}}}});}}}return tools;}
async function processFileAndScriptOperations(text,username,folderPath){let result={text,operations:[],fileContents:[],deleteFolders:[],urlContents:[]};if(!text)return result;let modifiedText=text;const processedOps=new Set();const userConfig=await loadUserConfig(username,'config.json',{});const perms=userConfig.permissions||{write:true,read:true,delete:false};const configs=userConfig.configs||{};if(perms.write){const writeRegex=/\[#-\](.*?)\[#-\]\s*\[#_\](.*?)\[#_\]/gs;let match;while((match=writeRegex.exec(text))!==null){const opKey=`write_${match[1]}_${match[2]}`;if(processedOps.has(opKey))continue;processedOps.add(opKey);let targetPath='';try{targetPath=match[1].trim();if(!path.isAbsolute(targetPath))targetPath=path.join(folderPath||currentPublicFolder,path.basename(targetPath));await fs.mkdir(path.dirname(targetPath),{recursive:true});await fs.writeFile(targetPath,match[2].trim());addLog(`📝 ${username} 写入文件: ${targetPath}`);result.operations.push({type:'write',path:targetPath,success:true});result.fileContents.push({path:targetPath,content:match[2].trim()});modifiedText=modifiedText.replace(match[0],`\n\n【已写入文件: ${targetPath}】\n\n`);}catch(e){addLog(`写入失败: ${targetPath||match[1]} - ${e.message}`);result.operations.push({type:'write',path:match[1],success:false,error:e.message});modifiedText=modifiedText.replace(match[0],`\n\n【写入失败: ${match[1]} - ${e.message}】\n\n`);}}}if(perms.read){const readRegex=/\[\+#\](.*?)\[\+#\]/g;let match;while((match=readRegex.exec(text))!==null){const opKey=`read_${match[1]}`;if(processedOps.has(opKey))continue;processedOps.add(opKey);let targetPath='';try{targetPath=match[1].trim();if(!path.isAbsolute(targetPath)){targetPath=path.join(folderPath||currentPublicFolder,targetPath);}const stats=await fs.stat(targetPath);let content='';if(stats.isDirectory()){const files=await fs.readdir(targetPath);let fileList='';for(const file of files){try{const filePath=path.join(targetPath,file);const fileStats=await fs.stat(filePath);fileList+=`${file}${fileStats.isDirectory()?'/':''}\n`;if(configs.readFolderNames){content+=`文件名: ${file}\n`;}}catch(e){fileList+=`${file} (无法访问)\n`;}}content='📁 文件夹内容:\n'+fileList;if(configs.readAllFileContents){content='';for(const file of files){try{const filePath=path.join(targetPath,file);const fileStats=await fs.stat(filePath);if(!fileStats.isDirectory()){const fileContent=await fs.readFile(filePath,'utf8');content+=`\n文件: ${file}\n内容:\n${fileContent}\n`;}}catch(e){content+=`\n文件: ${file} (无法读取)\n`;}}}}else{content=await fs.readFile(targetPath,'utf8');}result.fileContents.push({path:targetPath,content});addLog(`📖 ${username} 读取文件: ${targetPath}`);result.operations.push({type:'read',path:targetPath,success:true});modifiedText=modifiedText.replace(match[0],`\n\n【已读取文件: ${targetPath}】\n\n\`\`\`\n${content}\n\`\`\`\n\n`);}catch(e){addLog(`读取失败: ${match[1]} - ${e.message}`);result.operations.push({type:'read',path:match[1],success:false,error:e.message});modifiedText=modifiedText.replace(match[0],`\n\n【读取失败: ${match[1]} - ${e.message}】\n\n`);result.fileContents.push({path:match[1],content:`读取失败: ${e.message}`,success:false});}}}if(perms.delete){const deleteRegex=/\[-#\](.*?)\[-#\]/g;let match;while((match=deleteRegex.exec(text))!==null){const opKey=`delete_${match[1]}`;if(processedOps.has(opKey))continue;processedOps.add(opKey);let targetPath='';try{targetPath=match[1].trim();if(!path.isAbsolute(targetPath))targetPath=path.join(folderPath||currentPublicFolder,path.basename(targetPath));const stats=await fs.stat(targetPath);if(stats.isDirectory()){await fs.rmdir(targetPath,{recursive:true});result.deleteFolders.push(targetPath);addLog(`${username} 删除文件夹: ${targetPath}`);}else{await fs.unlink(targetPath);addLog(`${username} 删除文件: ${targetPath}`);}result.operations.push({type:'delete',path:targetPath,success:true});modifiedText=modifiedText.replace(match[0],`\n\n【已删除: ${targetPath}】\n\n`);}catch(e){addLog(`删除失败: ${match[1]} - ${e.message}`);result.operations.push({type:'delete',path:match[1],success:false,error:e.message});modifiedText=modifiedText.replace(match[0],`\n\n【删除失败: ${match[1]} - ${e.message}】\n\n`);}}}const curlRegex=/\[#!\](.*?)\[!#\]/g;let curlMatch;while((curlMatch=curlRegex.exec(text))!==null){const url=curlMatch[1].trim();const opKey=`curl_${url}`;if(processedOps.has(opKey))continue;processedOps.add(opKey);try{addLog(`🌐 CURL请求: ${url}`);const response=await axios.get(url,{timeout:10000,responseType:'text',headers:{'User-Agent':'Mozilla/5.0'}});result.urlContents.push({url,content:response.data});result.operations.push({type:'curl',url,success:true});modifiedText=modifiedText.replace(curlMatch[0],`\n\n【已获取URL内容: ${url}】\n\n\`\`\`\n${response.data.substring(0,1000)}${response.data.length>1000?'...':''}\n\`\`\`\n\n`);}catch(e){addLog(`CURL失败: ${url} - ${e.message}`);result.operations.push({type:'curl',url,success:false,error:e.message});modifiedText=modifiedText.replace(curlMatch[0],`\n\n【获取URL失败: ${url} - ${e.message}】\n\n`);}}result.text=modifiedText;return result;}
async function callAISecondary(provider,messages,toolResults,username,res,firstContent,firstReasoning,fileOperations,histories,currentHistoryId,tokenUsage,folder){try{messages.push({role:'assistant',content:firstContent,reasoning:firstReasoning,operations:fileOperations});histories[username][currentHistoryId].messages=messages;await saveHistories(histories);const newMessages=[...messages,{role:'user',content:`插件执行结果：\n${toolResults}`}];const activeKey=provider.keys?.find(k=>k.isActive)?.key;const apiBody={model:provider.model,messages:newMessages,stream:true,temperature:0.7,max_tokens:2000,top_p:0.9};const headers={'Content-Type':'application/json','Authorization':`Bearer ${activeKey}`};addLog(`调用二次AI处理插件结果: ${provider.name}/${provider.model}`);const response=await axios.post(provider.url,apiBody,{headers,timeout:120000,responseType:'stream'});let secondContent='';let secondReasoning='';response.data.on('data',chunk=>{const chunkStr=chunk.toString();const lines=chunkStr.split('\n');for(const line of lines){if(line.startsWith('data: ')&&line!=='data: [DONE]'){try{const data=JSON.parse(line.slice(6));if(data.choices?.[0]?.delta?.reasoning_content){secondReasoning+=data.choices[0].delta.reasoning_content;res.write(`data: ${JSON.stringify({reasoning:secondReasoning})}\n\n`);}if(data.choices?.[0]?.delta?.content){const delta=data.choices[0].delta.content;secondContent+=delta;res.write(`data: ${JSON.stringify({content:secondContent,reasoning:secondReasoning,delta})}\n\n`);}}catch(e){}}}});response.data.on('end',async()=>{messages.push({role:'assistant',content:secondContent,reasoning:secondReasoning,operations:fileOperations});histories[username][currentHistoryId].messages=messages;await saveHistories(histories);for(const op of fileOperations){res.write(`data: ${JSON.stringify({operationResult:op})}\n\n`);}res.write(`data: [DONE]\n\n`);res.end();});}catch(e){addLog(`❌ 二次AI调用失败: ${e.message}`);res.write(`data: ${JSON.stringify({error:e.message})}\n\n`);res.write(`data: [DONE]\n\n`);res.end();}}
app.post('/api/register',async(req,res)=>{try{const{username,password}=req.body;if(!username||!password)return res.status(400).json({error:'用户名密码必填'});await loadUsers();if(users[username])return res.status(400).json({error:'用户已存在'});users[username]={password,createdAt:new Date().toISOString()};await saveUsers();res.json({success:true});}catch(e){res.status(500).json({error:e.message});}});
app.post('/api/login',async(req,res)=>{try{const{username,password}=req.body;if(!username||!password)return res.status(400).json({error:'用户名密码必填'});await loadUsers();if(username==='admin')return res.status(401).json({error:'管理员请使用管理员登录按钮'});if(!users[username]||users[username].password!==password)return res.status(401).json({error:'用户名或密码错误'});const token=Math.random().toString(36).substring(2);sessions[token]={username,loginAt:new Date().toISOString()};await saveSessions();res.json({success:true,token,username});}catch(e){res.status(500).json({error:e.message});}});
app.post('/api/logout',async(req,res)=>{try{const{token}=req.body;if(sessions[token]){delete sessions[token];await saveSessions();}res.json({success:true});}catch(e){res.status(500).json({error:e.message});}});
app.get('/api/public-folders',async(req,res)=>{try{const{token}=req.query;if(!sessions[token])return res.status(401).json({error:'请先登录'});await loadPublicFolders();res.json(PUBLIC_DIRS);}catch(e){res.status(500).json({error:e.message});}});
app.post('/api/set-public-folder',async(req,res)=>{try{const{token,path}=req.body;if(!sessions[token])return res.status(401).json({error:'请先登录'});await loadPublicFolders();PUBLIC_DIRS.forEach(f=>f.active=false);const folder=PUBLIC_DIRS.find(f=>f.path===path);if(folder){folder.active=true;currentPublicFolder=path;await savePublicFolders();res.json({success:true});}else{res.status(404).json({error:'文件夹不存在'});}}catch(e){res.status(500).json({error:e.message});}});
app.post('/api/add-public-folder',async(req,res)=>{try{const{token,name,path}=req.body;if(!sessions[token])return res.status(401).json({error:'请先登录'});if(!sessions[token].isAdmin&&adminControls.disablePublicDirWrite){return res.status(403).json({error:'管理员已禁用添加公共文件夹'});}await loadPublicFolders();PUBLIC_DIRS.push({name,path,active:false});await savePublicFolders();res.json({success:true});}catch(e){res.status(500).json({error:e.message});}});
app.post('/api/delete-public-folder',async(req,res)=>{try{const{token,path}=req.body;if(!sessions[token])return res.status(401).json({error:'请先登录'});await loadPublicFolders();PUBLIC_DIRS=PUBLIC_DIRS.filter(f=>f.path!==path);await savePublicFolders();res.json({success:true});}catch(e){res.status(500).json({error:e.message});}});
app.get('/api/plugins',async(req,res)=>{try{const{token}=req.query;if(!sessions[token])return res.status(401).json({error:'请先登录'});const username=sessions[token].username;const isAdminUser=sessions[token].isAdmin===true;if(!isAdminUser&&adminControls.disablePlugins){return res.json([]);}await loadPlugins();res.json(plugins);}catch(e){res.status(500).json({error:e.message});}});
app.post('/api/toggle-plugin',async(req,res)=>{try{const{token,pluginId,enabled}=req.body;if(!sessions[token])return res.status(401).json({error:'请先登录'});const pluginConfigPath=path.join(PLUGINS_DIR,'plugins_config.json');let pluginConfig={};try{const data=await fs.readFile(pluginConfigPath,'utf8');pluginConfig=JSON.parse(data);}catch{}pluginConfig[pluginId]={enabled};await fs.writeFile(pluginConfigPath,JSON.stringify(pluginConfig,null,2));addLog(`🔌 插件${enabled?'启用':'禁用'}: ${pluginId}`);res.json({success:true});}catch(e){res.status(500).json({error:e.message});}});
app.post('/api/upload-plugin',pluginUpload.single('plugin'),async(req,res)=>{try{if(!req.file)return res.status(400).json({error:'没有文件'});const token=req.body.token;if(!sessions[token])return res.status(401).json({error:'请先登录'});if(!sessions[token].isAdmin&&adminControls.disablePluginUpload){return res.status(403).json({error:'管理员已禁用插件上传'});}const pluginPath=path.join(PLUGINS_DIR,req.file.originalname);await fs.writeFile(pluginPath,req.file.buffer);addLog(`📦 上传插件: ${req.file.originalname}`);await loadPlugins();res.json({success:true});}catch(e){res.status(500).json({error:e.message});}});
app.post('/api/stop-generation',async(req,res)=>{try{const{token,historyId,partialContent,partialReasoning}=req.body;if(!sessions[token])return res.status(401).json({error:'请先登录'});const username=sessions[token].username;const histories=await loadHistories();if(histories[username]?.[historyId]){const partialMsg={role:'assistant',content:partialContent||'[已中断]',reasoning:partialReasoning||'',reasoningTime:0,isPartial:true};histories[username][historyId].messages.push(partialMsg);await saveHistories(histories);}const genKey=`${username}_${historyId}`;if(activeGenerations.has(genKey)){activeGenerations.get(genKey).abort();activeGenerations.delete(genKey);}res.json({success:true});}catch(e){res.status(500).json({error:e.message});}});

async function loadPublicFolders(){try{const data=await fs.readFile(PUBLIC_DIRS_FILE,'utf8');PUBLIC_DIRS=JSON.parse(data);const active=PUBLIC_DIRS.find(d=>d.active);if(active)currentPublicFolder=active.path;}catch(e){await fs.writeFile(PUBLIC_DIRS_FILE,JSON.stringify(PUBLIC_DIRS,null,2));}}

app.post('/api/chat',async(req,res)=>{const startTime=Date.now();try{const{message,providerId,model,token,historyId,folder,enablePlugins}=req.body;if(!sessions[token])return res.status(401).json({error:'请先登录'});const username=sessions[token].username;addLog(`[${username}] 发送消息: ${message.substring(0,50)}${message.length>50?'...':''}`,'user');const genKey=`${username}_${historyId||'new'}`;const controller=new AbortController();activeGenerations.set(genKey,controller);req.on('close',()=>{if(activeGenerations.has(genKey)){activeGenerations.delete(genKey);}});const histories=await loadHistories();if(!histories[username])histories[username]={};let messages=[];let currentHistoryId=historyId;if(!currentHistoryId||!histories[username][currentHistoryId]){currentHistoryId=Date.now().toString();histories[username][currentHistoryId]={id:currentHistoryId,title:(message||'新对话').substring(0,20),messages:[],createdAt:new Date().toISOString()};await saveHistories(histories);if(!message||message.trim()==='')return res.json({historyId:currentHistoryId});}else messages=histories[username][currentHistoryId].messages;if(!message||message.trim()==='')return res.json({historyId:currentHistoryId});if(!providerId)return res.status(400).json({error:'providerId不能为空'});const userProviders=await loadUserConfig(username,'providers.json',providers);const provider=userProviders.find(p=>p.id===providerId);if(!provider)return res.status(400).json({error:`提供商不存在: ${providerId}`});const activeKey=provider.keys?.find(k=>k.isActive)?.key;if(!activeKey)return res.status(400).json({error:`${provider.name} 未配置有效API Key`});if(!model)return res.status(400).json({error:'请选择模型'});addLog(`[${username}] API调用 - 聊天请求: ${provider.name}/${model}`,'api');const promptConfig=await loadPromptConfig();let sysContent=promptConfig.system||'';const userConfig=await loadUserConfig(username,'config.json',{});const perms=userConfig.permissions||{write:true,read:true,delete:false};if(userConfig.configs?.systemPrompt){sysContent+=`\n${userConfig.configs.systemPrompt}`;}if(userConfig.configs?.persistentFolder){sysContent+=`\n你可以常驻读取的文件夹: ${userConfig.configs.persistentFolder}`;}if(userConfig.configs?.modelPrompt&&userConfig.configs.modelPrompt!=='无'&&userConfig.configs.modelPrompt!==''){messages.push({role:'system',content:userConfig.configs.modelPrompt});}messages.push({role:'user',content:message});await loadPlugins();let finalMessages=[];if(userConfig.configs?.modelPrompt&&userConfig.configs.modelPrompt!==''&&userConfig.configs.modelPrompt!==''){finalMessages.push({role:'system',content:userConfig.configs.modelPrompt});}finalMessages.push({role:'system',content:sysContent||''});finalMessages=finalMessages.concat(messages);const apiBody={model,messages:finalMessages,temperature:userConfig.configs?.temperature||0.7,max_tokens:userConfig.configs?.maxTokens||2000,top_p:userConfig.configs?.topP||0.9,stream:true};if(enablePlugins&&plugins.length>0&&userConfig.configs?.enablePlugins!==false){const tools=await getPluginTools();if(tools.length>0){apiBody.tools=tools;apiBody.tool_choice='auto';}}const headers={'Content-Type':'application/json','Authorization':`Bearer ${activeKey}`};let response;let tokenUsage={};try{response=await axios.post(provider.url,apiBody,{headers,timeout:120000,responseType:'stream',signal:controller.signal});}catch(e){addLog(`❌ API调用失败: ${e.message}`,'error');activeGenerations.delete(genKey);return res.json({error:`API调用失败: ${e.message}`});}res.setHeader('Content-Type','text/event-stream');res.setHeader('Cache-Control','no-cache');res.setHeader('Connection','keep-alive');let fullContent='';let reasoningContent='';let fileOperations=[];let hasExecutedSecondary=false;let toolCalls=[];let hasReceivedAnyData=false;let providerResponse='';response.data.on('data',chunk=>{if(controller.signal.aborted){response.data.destroy();return;}if(chunk===null||chunk===undefined)return;if(!hasReceivedAnyData){hasReceivedAnyData=true;res.write(`data: ${JSON.stringify({received:true})}\n\n`);}const chunkStr=chunk.toString();providerResponse+=chunkStr;const lines=chunkStr.split('\n');for(const line of lines){if(!line)continue;if(line.startsWith('data: ')&&line!=='data: [DONE]'){try{const data=JSON.parse(line.slice(6));if(data.choices?.[0]?.delta?.tool_calls){const deltaTools=data.choices[0].delta.tool_calls;const newTools=[];deltaTools.forEach(deltaTool=>{let existing=toolCalls.find(t=>t.index===deltaTool.index);if(existing){if(deltaTool.function?.arguments){existing.function.arguments+=deltaTool.function.arguments;}}else{const newTool={index:deltaTool.index,id:deltaTool.id||`tool_${Date.now()}_${deltaTool.index}`,type:deltaTool.type,function:{name:deltaTool.function?.name||'',arguments:deltaTool.function?.arguments||''}};toolCalls.push(newTool);newTools.push(newTool);}});if(newTools.length>0){res.write(`data: ${JSON.stringify({toolCalls:newTools.map(t=>({name:t.function.name}))})}\n\n`);}}if(data.choices?.[0]?.delta?.reasoning_content){const reasoningDelta=data.choices[0].delta.reasoning_content;reasoningContent+=reasoningDelta;res.write(`data: ${JSON.stringify({reasoning:reasoningContent,reasoningDelta})}\n\n`);}if(data.choices?.[0]?.delta?.content){const delta=data.choices[0].delta.content;fullContent+=delta;res.write(`data: ${JSON.stringify({content:fullContent,reasoning:reasoningContent,delta})}\n\n`);}if(data.usage)tokenUsage=data.usage;}catch(e){}}}});response.data.on('end',async()=>{if(controller.signal.aborted)return;activeGenerations.delete(genKey);if(hasExecutedSecondary)return;if(toolCalls.length>0&&enablePlugins&&userConfig.configs?.enablePlugins!==false){recordModelCall(username,providerId,model);addLog(`📊 记录模型调用: ${providerId}/${model} (工具调用)`);}if(toolCalls.length>0&&enablePlugins&&userConfig.configs?.enablePlugins!==false){const uniqueTools=[];const seenNames=new Set();toolCalls.forEach(tool=>{if(tool.function?.name&&!seenNames.has(tool.function.name)){seenNames.add(tool.function.name);uniqueTools.push(tool);}});hasExecutedSecondary=true;let toolResults='';let pluginOutputs=[];res.write(`data: ${JSON.stringify({pluginCalling:true,plugins:uniqueTools.map(t=>t.function.name)})}\n\n`);const authPath=path.join(DATA_DIR,'users',username,'plugin_auth.json');let auth={};try{auth=JSON.parse(await fs.readFile(authPath,'utf8'));}catch{}for(const tool of uniqueTools){const functionName=tool.function?.name||'';let args={};if(tool.function&&tool.function.arguments){try{args=JSON.parse(tool.function.arguments);}catch(e){args={};}}if(functionName){addLog(`🔧 执行插件函数: ${functionName}`,'plugin');res.write(`data: ${JSON.stringify({pluginCalling:{name:functionName,args:args,status:'calling'}})}\n\n`);try{const result=await callPluginFunction('',functionName,args);const pluginDisplay=`插件已调用：${functionName} ${result.success?'✓':'✗'}`;pluginOutputs.push({plugin:functionName,success:result.success,output:result.output||'',error:result.error||'',display:pluginDisplay,args:args});if(result.success){toolResults+=`\n【${functionName}】\n${result.output||'执行成功'}\n`;}else{toolResults+=`\n【${functionName}】\n执行失败: ${result.error||'未知错误'}\n`;}fileOperations.push({type:'plugin',plugin:functionName,function:functionName,success:result.success,error:result.error,output:result.output,args:args});}catch(e){const pluginDisplay=`插件已调用：${functionName} ✗`;pluginOutputs.push({plugin:functionName,success:false,error:e.message,display:pluginDisplay,args:args});toolResults+=`\n【${functionName}】\n执行失败: ${e.message}\n`;}}}res.write(`data: ${JSON.stringify({pluginResult:'插件执行完成',pluginDetails:pluginOutputs,operations:fileOperations})}\n\n`);await callAISecondary({...provider,model},messages,toolResults,username,res,fullContent,reasoningContent,fileOperations,histories,currentHistoryId,tokenUsage,folder);}else{const opResult=await processFileAndScriptOperations(fullContent,username,folder);fileOperations=opResult.operations;let combinedContent=opResult.text;if(opResult.urlContents&&opResult.urlContents.length>0){let urlText='\n\n【获取的URL内容】\n';opResult.urlContents.forEach(u=>{urlText+=`URL: ${u.url}\n内容:\n\`\`\`\n${u.content}\n\`\`\`\n\n`;});combinedContent+=urlText;}if(opResult.fileContents&&opResult.fileContents.length>0){addLog(`📚 检测到${opResult.fileContents.length}个文件读取，准备继续`,'info');res.write(`data: ${JSON.stringify({fileReading:true,count:opResult.fileContents.length})}\n\n`);}if(opResult.deleteFolders&&opResult.deleteFolders.length>0){addLog(`检测到${opResult.deleteFolders.length}个文件夹删除`,'info');}messages.push({role:'assistant',content:combinedContent,reasoning:reasoningContent,reasoningTime:Math.round((Date.now()-startTime)/1000),operations:fileOperations,tokenUsage});if(userConfig.configs?.showTokenUsage&&tokenUsage){messages[messages.length-1].tokenUsage=tokenUsage;}histories[username][currentHistoryId].messages=messages;await recordModelCall(username,providerId,model);await saveHistories(histories);for(const op of fileOperations){res.write(`data: ${JSON.stringify({operationResult:op})}\n\n`);}res.write(`data: [DONE]\n\n`);res.end();}});}catch(e){activeGenerations.delete(`${sessions[req.body.token]?.username}_${req.body.historyId||'new'}`);addLog(`❌ 聊天处理异常: ${e.message}`,'error');if(!res.headersSent){res.status(500).json({error:e.message});}}});


