app.post('/api/edit-user-message',async(req,res)=>{try{const{token,historyId,messageIndex,newContent}=req.body;if(!sessions[token])return res.status(401).json({error:'请先登录'});const username=sessions[token].username;const histories=await loadHistories();const history=histories[username]?.[historyId];if(!history)return res.status(404).json({error:'历史不存在'});if(!history.branches)history.branches=[];if(history.currentBranch===undefined)history.currentBranch=0;const currentMessages=history.messages;const branchExists=history.branches.some(b=>JSON.stringify(b.messages)===JSON.stringify(currentMessages));if(!branchExists)history.branches.push({messages:currentMessages,createdAt:new Date().toISOString()});const newMessages=currentMessages.slice(0,messageIndex);newMessages.push({role:'user',content:newContent});history.branches.push({messages:newMessages,createdAt:new Date().toISOString()});history.currentBranch=history.branches.length-1;history.messages=newMessages;await saveHistories(histories);res.json({success:true,newBranchIndex:history.currentBranch,messages:newMessages});}catch(e){res.status(500).json({error:e.message});}});
