app.get('/api/files',async(req,res)=>{try{let folder=req.query.folder;if(!folder||folder==='\\'||folder==='%5C')folder=currentPublicFolder;const dir=req.query.path||'';const token=req.query.token;if(!sessions[token])return res.status(401).json({error:'请先登录'});const username=sessions[token].username;const targetPath=path.join(folder,dir);await fs.access(targetPath);const items=await fs.readdir(targetPath);const statusMap=await loadFolderStatus();const details=await Promise.all(items.map(async(item)=>{const itemPath=path.join(targetPath,item);const stat=await fs.stat(itemPath);const relativePath=path.join(dir,item);const fullPath=path.join(folder,relativePath);const status=statusMap[fullPath];if(stat.isDirectory()&&status&&status.status==='private'&&status.owner!==username)return null;return{name:item,path:relativePath,isDirectory:stat.isDirectory(),size:stat.size,modified:stat.mtime,status:status?status.status:'public'};}));res.json(details.filter(Boolean));}catch(e){res.status(500).json({error:e.message});}});
