app.post('/api/providers/update-balance',async(req,res)=>{try{const token=req.query.token;if(!sessions[token])return res.status(401).json({error:'请先登录'});const username=sessions[token].username;const{providerId,keyId,balance}=req.body;let userProviders=await loadUserConfig(username,'providers.json',providers);const provider=userProviders.find(p=>p.id===providerId);if(!provider)return res.status(404).json({error:'提供商不存在'});const keyObj=provider.keys.find(k=>k.id===keyId);if(keyObj)keyObj.balance=balance;await saveUserConfig(username,'providers.json',userProviders);addLog(`💰 ${provider.name} 余额更新: ${balance} 用户=${username}`);res.json({success:true});}catch(e){res.status(500).json({error:e.message});}});
app.delete('/api/providers/key/:providerId/:keyId',async(req,res)=>{try{const token=req.query.token;if(!sessions[token])return res.status(401).json({error:'请先登录'});const username=sessions[token].username;let userProviders=await loadUserConfig(username,'providers.json',providers);const provider=userProviders.find(p=>p.id===req.params.providerId);if(!provider)return res.status(404).json({error:'提供商不存在'});provider.keys=provider.keys.filter(k=>k.id!==req.params.keyId);if(provider.keys.length>0&&!provider.keys.some(k=>k.isActive)){provider.keys[0].isActive=true;}await saveUserConfig(username,'providers.json',userProviders);res.json({success:true});}catch(e){res.status(500).json({error:e.message});}});
app.delete('/api/providers/:id',async(req,res)=>{try{const token=req.query.token;if(!sessions[token])return res.status(401).json({error:'请先登录'});const username=sessions[token].username;let userProviders=await loadUserConfig(username,'providers.json',providers);userProviders=userProviders.filter(p=>p.id!==req.params.id);await saveUserConfig(username,'providers.json',userProviders);res.json(userProviders);}catch(e){res.status(500).json({error:e.message});}});
app.get('/api/random-users',async(req,res)=>{try{const{token}=req.query;if(!sessions[token])return res.status(401).json({error:'请先登录'});const currentUser=sessions[token].username;const allUsers=Object.keys(users).filter(u=>u!==currentUser);const profiles=await Promise.all(allUsers.map(async u=>{const profile=await loadUserConfig(u,'profile.json',{avatar:'',name:u,public:true});return{username:u,avatar:profile.avatar,name:profile.name,public:profile.public,online:onlineUsers.has(u)};}));const publicUsers=profiles.filter(p=>p.public!==false);const shuffled=publicUsers.sort(()=>0.5-Math.random());const selected=shuffled.slice(0,10);res.json(selected);}catch(e){res.status(500).json({error:e.message});}});
app.get('/api/search-users',async(req,res)=>{try{const{token,query}=req.query;if(!sessions[token])return res.status(401).json({error:'请先登录'});const currentUser=sessions[token].username;const allUsers=Object.keys(users).filter(u=>u!==currentUser);const profiles=await Promise.all(allUsers.map(async u=>{const profile=await loadUserConfig(u,'profile.json',{avatar:'',name:u,public:true});return{username:u,avatar:profile.avatar,name:profile.name,public:profile.public,online:onlineUsers.has(u)};}));const matched=profiles.filter(p=>p.public!==false&&(p.username.includes(query)||p.name.includes(query))).slice(0,20);res.json(matched);}catch(e){res.status(500).json({error:e.message});}});
app.get('/api/private-messages/:friend',async(req,res)=>{try{const{token}=req.query;const friend=req.params.friend;if(!sessions[token])return res.status(401).json({error:'请先登录'});const currentUser=sessions[token].username;const key=[currentUser,friend].sort().join('_');await loadPrivateMessages();res.json(privateMessages[key]||[]);}catch(e){res.status(500).json({error:e.message});}});
app.get('/api/online-count',(req,res)=>{res.json({count:onlineUsers.size});});
app.get('/api/my-ip',(req,res)=>{const ip=req.headers['x-forwarded-for']||req.socket.remoteAddress;res.json({ip});});
app.post('/api/profile',async(req,res)=>{try{const{token,avatar,name,public:isPublic}=req.body;if(!sessions[token])return res.status(401).json({error:'请先登录'});const username=sessions[token].username;let profile=await loadUserConfig(username,'profile.json',{avatar:'/image/user.png',name:username,public:true});if(avatar!==undefined)profile.avatar=avatar;if(name!==undefined)profile.name=name;if(isPublic!==undefined)profile.public=isPublic;await saveUserConfig(username,'profile.json',profile);res.json({success:true});}catch(e){res.status(500).json({error:e.message});}});
app.post('/api/change-password',async(req,res)=>{try{const{token,oldPassword,newPassword}=req.body;if(!sessions[token])return res.status(401).json({error:'请先登录'});const username=sessions[token].username;await loadUsers();if(users[username].password!==oldPassword)return res.status(400).json({error:'旧密码错误'});users[username].password=newPassword;await saveUsers();res.json({success:true});}catch(e){res.status(500).json({error:e.message});}});
app.post('/api/admin/login',async(req,res)=>{try{const{key}=req.body;if(key!==ADMIN_KEY)return res.status(401).json({error:'密钥错误'});const token=Math.random().toString(36).substring(2);sessions[token]={username:'admin',loginAt:new Date().toISOString(),isAdmin:true};await saveSessions();res.json({success:true,token,username:'admin',isAdmin:true});}catch(e){res.status(500).json({error:e.message});}});
app.get('/api/admin/users',async(req,res)=>{try{const{token}=req.query;if(!sessions[token]||!sessions[token].isAdmin)return res.status(401).json({error:'需要管理员权限'});await loadUsers();const userList=Object.keys(users).map(u=>({username:u,createdAt:users[u].createdAt}));res.json(userList);}catch(e){res.status(500).json({error:e.message});}});
app.delete('/api/admin/users/:username',async(req,res)=>{try{const{token}=req.query;if(!sessions[token]||!sessions[token].isAdmin)return res.status(401).json({error:'需要管理员权限'});const username=req.params.username;if(username==='admin')return res.status(400).json({error:'不能删除管理员'});await loadUsers();delete users[username];await saveUsers();const histories=await loadHistories();delete histories[username];await saveHistories(histories);res.json({success:true});}catch(e){res.status(500).json({error:e.message});}});
app.post('/api/admin/restart',async(req,res)=>{try{const{token}=req.body;if(!sessions[token]||!sessions[token].isAdmin){return res.status(401).json({error:'需要管理员权限'});}addLog('管理员请求重启服务器...','info');res.json({success:true});setTimeout(()=>{server.close(()=>{io.close(()=>{for(const[key,controller]of activeGenerations){controller.abort();}activeGenerations.clear();setTimeout(()=>{const{spawn}=require('child_process');const child=spawn('node',[process.argv[1],...process.argv.slice(2)],{cwd:process.cwd(),detached:true,stdio:'inherit',env:{...process.env,RESTARTED:'true'}});child.unref();setTimeout(()=>process.exit(0),500);},1000);});});},1000);}catch(e){res.status(500).json({error:e.message});}});
app.get('/api/admin/controls',async(req,res)=>{try{const{token}=req.query;if(!sessions[token]||!sessions[token].isAdmin)return res.status(401).json({error:'需要管理员权限'});res.json(adminControls);}catch(e){res.status(500).json({error:e.message});}});
app.post('/api/admin/controls',async(req,res)=>{try{const{token}=req.query;if(!sessions[token]||!sessions[token].isAdmin)return res.status(401).json({error:'需要管理员权限'});const{disablePlugins,disablePluginUpload,disableNoticeEdit,disablePublicDirWrite}=req.body;if(disablePlugins!==undefined)adminControls.disablePlugins=disablePlugins;if(disablePluginUpload!==undefined)adminControls.disablePluginUpload=disablePluginUpload;if(disableNoticeEdit!==undefined)adminControls.disableNoticeEdit=disableNoticeEdit;if(disablePublicDirWrite!==undefined)adminControls.disablePublicDirWrite=disablePublicDirWrite;await saveAdminControls();res.json({success:true});}catch(e){res.status(500).json({error:e.message});}});

app.post('/api/set-folder-status',async(req,res)=>{try{const{token,path,status,password}=req.body;if(!sessions[token])return res.status(401).json({error:'请先登录'});const username=sessions[token].username;const fullPath=path.join(currentPublicFolder,path);const stat=await fs.stat(fullPath);if(!stat.isDirectory())return res.status(400).json({error:'只能设置文件夹状态'});const statusMap=await loadFolderStatus();statusMap[fullPath]={owner:username,status,password:password||''};await saveFolderStatus(statusMap);addLog(`📁 文件夹状态更新: ${path} -> ${status} 用户=${username}`);res.json({success:true});}catch(e){res.status(500).json({error:e.message});}});
app.post('/api/verify-folder-password',async(req,res)=>{try{const{token,path,password}=req.body;if(!sessions[token])return res.status(401).json({error:'请先登录'});const username=sessions[token].username;const fullPath=path.join(currentPublicFolder,path);const statusMap=await loadFolderStatus();const status=statusMap[fullPath];if(!status||status.status!=='private')return res.json({success:false,error:'不是私密文件夹'});if(status.owner===username)return res.json({success:true});if(status.password===password)return res.json({success:true});else return res.json({success:false,error:'密码错误'});}catch(e){res.status(500).json({error:e.message});}});
app.get('/api/private-chats',async(req,res)=>{try{const{token}=req.query;if(!sessions[token])return res.status(401).json({error:'请先登录'});const username=sessions[token].username;await loadPrivateChats();const userChats=privateChats[username]||[];res.json(userChats);}catch(e){res.status(500).json({error:e.message});}});
app.post('/api/private-chats',async(req,res)=>{try{const{token,friend,pinned}=req.body;if(!sessions[token])return res.status(401).json({error:'请先登录'});const username=sessions[token].username;await loadPrivateChats();if(!privateChats[username])privateChats[username]=[];let chat=privateChats[username].find(c=>c.friend===friend);if(!chat){chat={friend,pinned:!!pinned,lastMessageTime:Date.now()};privateChats[username].push(chat);}else{chat.pinned=!!pinned;chat.lastMessageTime=Date.now();}await savePrivateChats();res.json({success:true});}catch(e){res.status(500).json({error:e.message});}});
app.delete('/api/private-chats/:friend',async(req,res)=>{try{const{token}=req.query;if(!sessions[token])return res.status(401).json({error:'请先登录'});const username=sessions[token].username;await loadPrivateChats();if(privateChats[username]){privateChats[username]=privateChats[username].filter(c=>c.friend!==req.params.friend);await savePrivateChats();}res.json({success:true});}catch(e){res.status(500).json({error:e.message});}});
app.get('/api/prompt',async(req,res)=>{try{const promptConfig=await loadPromptConfig();res.json(promptConfig);}catch(e){res.status(500).json({error:e.message});}});
app.post('/api/prompt',async(req,res)=>{try{const{token,system}=req.body;if(!sessions[token])return res.status(401).json({error:'请先登录'});await savePromptConfig({system});addLog(`📝 提示词已更新`);res.json({success:true});}catch(e){res.status(500).json({error:e.message});}});
io.use((socket,next)=>{const token=socket.handshake.auth.token;if(!token||!sessions[token])return next(new Error('认证失败'));socket.username=sessions[token].username;next();}).on('connection',(socket)=>{const username=socket.username;onlineUsers.set(username,socket.id);socket.join(username);io.emit('online-count',onlineUsers.size);socket.on('private-message',async(data)=>{const{to,content,type='text',fileData}=data;if(!to||!content)return;const key=[username,to].sort().join('_');await loadPrivateMessages();if(!privateMessages[key])privateMessages[key]=[];const message={from:username,to,content,type,fileData,timestamp:Date.now()};privateMessages[key].push(message);await savePrivateMessages();if(type==='gift'){await loadUserRelations();if(!userRelations[username])userRelations[username]={};if(!userRelations[username][to])userRelations[username][to]={intimacy:0,pinned:false};userRelations[username][to].intimacy+=10;await saveUserRelations();}await loadPrivateChats();if(!privateChats[username])privateChats[username]=[];let chat=privateChats[username].find(c=>c.friend===to);if(!chat){privateChats[username].push({friend:to,pinned:false,lastMessageTime:Date.now()});}else{chat.lastMessageTime=Date.now();}await savePrivateChats();io.to(to).emit('private-message',message);socket.emit('private-message',message);});socket.on('disconnect',()=>{onlineUsers.delete(username);io.emit('online-count',onlineUsers.size);});});
